{
    "level": "B2",
    "intro": "In this topic, you will learn <strong>impersonal/report passive</strong> - formal constructions for conveying thoughts, messages, rumors: <strong>It is said that...</strong>, <strong>He is believed to...</strong>.",
    "rules": [
        {
            "label": "Impersonal",
            "color": "emerald",
            "text": "Impersonal construction: <strong>It is said/believed that...</strong>",
            "example": "It is said that he is very rich."
        },
        {
            "label": "Personal",
            "color": "blue",
            "text": "Personal construction: <strong>He is said/believed to...</strong>",
            "example": "He is said to be very rich."
        },
        {
            "label": "Style",
            "color": "rose",
            "text": "Formal style: news, science, official texts",
            "example": "It is reported that the talks have failed."
        }
    ]
}

{
    "title": "1. Impersonal construction: It is said/believed that...",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "<strong>It + is/was + V3 (reporting verb) + that + clause</strong>",
            "examples": [
                {
                    "en": "Active: People say that he is very rich.",
                    "ua": "Active: People say that he is very rich."
                },
                {
                    "en": "Passive: It is said that he is very rich.",
                    "ua": "Passive: It is said that he is very rich."
                }
            ]
        },
        {
            "label": "It is believed",
            "color": "sky",
            "description": "To convey <strong>beliefs, opinions</strong>.",
            "examples": [
                {
                    "en": "It is believed that the universe is expanding.",
                    "ua": "It is believed that the universe is expanding."
                },
                {
                    "en": "It was believed that the Earth was flat.",
                    "ua": "It was believed that the Earth was flat."
                }
            ]
        },
        {
            "label": "It is reported",
            "color": "blue",
            "description": "To transmit <strong>news, messages</strong>.",
            "examples": [
                {
                    "en": "It is reported that the storm is approaching.",
                    "ua": "It is reported that the storm is approaching."
                },
                {
                    "en": "It was reported that the talks had failed.",
                    "ua": "It was reported that the talks had failed."
                }
            ]
        },
        {
            "label": "It is known",
            "color": "amber",
            "description": "To convey <strong>commonly known facts</strong>.",
            "examples": [
                {
                    "en": "It is known that smoking causes cancer.",
                    "ua": "It is known that smoking causes cancer."
                },
                {
                    "en": "It is widely known that she is an expert.",
                    "ua": "It is widely known that she is an expert."
                }
            ]
        }
    ]
}

{
    "title": "2. Personal construction: He is said/believed to...",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "<strong>Subject + is/was + V3 + to + infinitive</strong>",
            "examples": [
                {
                    "en": "Active: People say that he is very rich.",
                    "ua": "Active: People say that he is very rich."
                },
                {
                    "en": "Passive: He is said to be very rich.",
                    "ua": "Passive: He is said to be very rich."
                }
            ]
        },
        {
            "label": "Current actions",
            "color": "sky",
            "description": "<strong>to + infinitive</strong> — when the action is simultaneous with the moment of speech.",
            "examples": [
                {
                    "en": "She is believed to live in Paris.",
                    "ua": "She is believed to live in Paris."
                },
                {
                    "en": "He is thought to be the best candidate.",
                    "ua": "He is thought to be the best candidate."
                }
            ]
        },
        {
            "label": "Past actions",
            "color": "blue",
            "description": "<strong>to have + V3</strong> - when the action happened earlier.",
            "examples": [
                {
                    "en": "She is believed to have left the country.",
                    "ua": "She is believed to have left the country."
                },
                {
                    "en": "He is said to have written many books.",
                    "ua": "He is said to have written many books."
                }
            ]
        },
        {
            "label": "Ongoing actions",
            "color": "amber",
            "description": "<strong>to be + V-ing</strong> - when the action is ongoing.",
            "examples": [
                {
                    "en": "They are reported to be negotiating.",
                    "ua": "They are reported to be negotiating."
                },
                {
                    "en": "He is believed to be working on a new project.",
                    "ua": "He is believed to be working on a new project."
                }
            ]
        }
    ]
}

{
    "title": "3. Typical reporting verbs",
    "sections": [
        {
            "label": "say / tell",
            "color": "emerald",
            "description": "<strong>say</strong> — for general statements. <strong>tell</strong> - less often in the impersonal.",
            "examples": [
                {
                    "en": "It is said that he resigned.",
                    "ua": "It is said that he resigned."
                },
                {
                    "en": "He is said to have resigned.",
                    "ua": "He is said to have resigned."
                }
            ]
        },
        {
            "label": "believe / think",
            "color": "blue",
            "description": "<strong>believe, think</strong> — for thoughts and beliefs.",
            "examples": [
                {
                    "en": "It is believed that the plan will work.",
                    "ua": "It is believed that the plan will work."
                },
                {
                    "en": "She is thought to be an expert.",
                    "ua": "She is thought to be an expert."
                }
            ]
        },
        {
            "label": "report / announce",
            "color": "sky",
            "description": "<strong>report, announce</strong> — for official announcements.",
            "examples": [
                {
                    "en": "It was reported that 50 people were injured.",
                    "ua": "It was reported that 50 people were injured."
                },
                {
                    "en": "The company is reported to be closing.",
                    "ua": "The company is reported to be closing."
                }
            ]
        },
        {
            "label": "expect / suppose",
            "color": "amber",
            "description": "<strong>expect, suppose, consider</strong> — for expectations and assumptions.",
            "examples": [
                {
                    "en": "It is expected that prices will rise.",
                    "ua": "It is expected that prices will rise."
                },
                {
                    "en": "She is supposed to arrive at 5.",
                    "ua": "She is supposed to arrive at 5."
                },
                {
                    "en": "He is considered to be a genius.",
                    "ua": "He is considered to be a genius."
                }
            ]
        },
        {
            "label": "know / understand",
            "color": "rose",
            "description": "<strong>know, understand</strong> — for facts and understanding.",
            "examples": [
                {
                    "en": "It is known that water boils at 100°C.",
                    "ua": "It is known that water boils at 100°C."
                },
                {
                    "en": "He is understood to have accepted the offer.",
                    "ua": "He is understood to have accepted the offer."
                }
            ]
        }
    ]
}

{
    "title": "4. Impersonal vs Personal passive",
    "intro": "Both constructions convey the same meaning, but with a different focus:",
    "rows": [
        {
            "en": "It is said that he is rich.",
            "ua": "It is said that he is rich.",
            "note": "Focus on facts, neutral."
        },
        {
            "en": "He is said to be rich.",
            "ua": "He is said to be rich.",
            "note": "Focus on the person, in short."
        },
        {
            "en": "It is believed that she left.",
            "ua": "It is believed that she left.",
            "note": "She is believed to have left."
        },
        {
            "en": "It was reported that they won.",
            "ua": "It was reported that they won.",
            "note": "They were reported to have won."
        }
    ],
    "warning": "📌 The personal construction often sounds <strong>more natural</strong> in modern English."
}

{
    "title": "5. Transformation: Active → Passive",
    "sections": [
        {
            "label": "Step 1",
            "color": "emerald",
            "description": "Identify the main verb (say, believe, think...) and the subordinate clause.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "People say that he is a genius."
                }
            ]
        },
        {
            "label": "Step 2: It-structure",
            "color": "sky",
            "description": "Make <strong>It</strong> subject + is/was + V3 + that-clause.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "People say that he is a genius."
                }
            ]
        },
        {
            "label": "Step 3: Subject-structure",
            "color": "blue",
            "description": "Make the subject of the subordinate clause the main + is/was + V3 + to-infinitive.",
            "examples": [
                {
                    "en": "People say that he is a genius.",
                    "ua": "People say that he is a genius."
                },
                {
                    "en": "People believed that she had left.",
                    "ua": "People believed that she had left."
                }
            ]
        }
    ]
}

{
    "title": "6. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Omission of \"to\" before the infinitive.",
            "wrong": "He is said be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Tense confusion: past actions with the simple infinitive.",
            "wrong": "She is believed to leave yesterday.",
            "right": "✅ She is believed to have left yesterday."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Using \"that\" in subject-structure.",
            "wrong": "He is said that to be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Omission of \"that\" in It-structure.",
            "wrong": "It is said he is rich.",
            "right": "✅ It is said that he is rich."
        }
    ]
}
